@PostMapping("/complete")
public ResponseEntity<TopicProgressResponse> completar(@Valid @RequestBody CompleteTopicRequest request) {
    TopicProgressResponse response = progressService.marcarComoCompleto(request);
    return ResponseEntity.status(HttpStatus.CREATED).body(response); // 201: recurso de progresso criado/atualizado
}

@ExceptionHandler(TopicNotFoundException.class)
public ResponseEntity<ErrorResponse> handleNotFound(TopicNotFoundException ex) {
    return ResponseEntity.status(HttpStatus.NOT_FOUND) // 404: o slug pedido não existe
        .body(new ErrorResponse("TOPIC_NOT_FOUND", ex.getMessage(), LocalDateTime.now()));
}

codeExampleBad:
// Retornar sempre 200, mesmo em caso de erro — obriga o cliente a inspecionar
// o BODY pra saber se deu certo, em vez de confiar no status HTTP (que é pra isso)
@GetMapping("/{slug}")
public ResponseEntity<Map<String, Object>> buscar(@PathVariable String slug) {
    Optional<Topic> topic = topicRepository.findBySlug(slug);
    if (topic.isEmpty()) {
        // Errado: deveria ser 404, não 200 com uma flag "sucesso: false" no corpo
        return ResponseEntity.ok(Map.of("sucesso", false, "erro", "não encontrado"));
    }
    return ResponseEntity.ok(Map.of("sucesso", true, "dados", topic.get()));
}

